var item = $input.first().json;
var data = item.output || '';

// Step 1: Extract JSON from ```json...``` code blocks or raw text
var jsonStr;
var fenceMatch = data.match(/```(?:json)?\s*\n?([\s\S]*?)\n?\s*```/);
if (fenceMatch) {
  jsonStr = fenceMatch[1].trim();
} else {
  var start = data.indexOf('{');
  var end = data.lastIndexOf('}');
  if (start >= 0 && end > start) {
    jsonStr = data.substring(start, end + 1);
  } else {
    jsonStr = data;
  }
}

// Step 2: Clean common LLM JSON issues
jsonStr = jsonStr
  .replace(/\]\s*\],/g, '],')   // duplicate ] before ,
  .replace(/\}\s*\},/g, '},')   // duplicate } before ,
  .replace(/\]\s*\]\s*\}/g, ']}') // duplicate ] before }
  .replace(/,\s*\]/g, ']')       // trailing comma before ]
  .replace(/,\s*\}/g, '}');      // trailing comma before }

// Step 3: Parse with fallback
var parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch(e1) {
  // Try extracting just the outermost { to }
  var s2 = jsonStr.indexOf('{');
  var e2 = jsonStr.lastIndexOf('}');
  if (s2 >= 0 && e2 > s2) {
    try {
      parsed = JSON.parse(jsonStr.substring(s2, e2 + 1));
    } catch(e3) {
      parsed = { sitrep: {
        generated_at: new Date().toISOString(),
        bluf: ['SITREP generation produced invalid JSON. Error: ' + e1.message + '. Raw length: ' + data.length + ' chars.'],
        strategic_landscape: {doge_watch:'Unavailable - JSON parse error',indopacom:'Unavailable - JSON parse error'},
        defensive_watch: {incumbency_threat:'Unavailable',market_pressure:'Unavailable'},
        strategic_synthesis: 'Re-run SITREP to regenerate.',
        threat_opportunity_matrix: [],
        recommendations: [{action:'Re-run Daily SITREP',owner:'System',deadline:'Today',why:'Previous generation produced malformed JSON'}],
        red_team: [],
        command_control: {title:'SITREP Parse Error',takeaway:'Re-run required',source:''},
        sam_gov_opportunities: [],
        top_news: []
      }};
    }
  } else {
    parsed = { sitrep: {
      generated_at: new Date().toISOString(),
      bluf: ['SITREP generation returned no JSON object. Raw length: ' + data.length],
      strategic_landscape: {doge_watch:'Unavailable',indopacom:'Unavailable'},
      defensive_watch: {incumbency_threat:'Unavailable',market_pressure:'Unavailable'},
      strategic_synthesis: 'Re-run SITREP.',
      threat_opportunity_matrix: [],
      recommendations: [],
      red_team: [],
      command_control: {title:'Error',takeaway:'Re-run',source:''},
      sam_gov_opportunities: [],
      top_news: []
    }};
  }
}
var s = parsed.sitrep || parsed;

var today = new Date().toLocaleDateString('en-US', {weekday:'long', year:'numeric', month:'long', day:'numeric'});

function renderWithSource(text) {
  if (!text) return 'Data Unavailable';
  var srcIdx = text.indexOf('| Source:');
  if (srcIdx === -1) srcIdx = text.indexOf('| source:');
  if (srcIdx !== -1) {
    var body = text.substring(0, srcIdx).trim();
    var url = text.substring(srcIdx + 9).trim().split(' ')[0];
    return body + ' <a href="' + url + '" style="color:#1a3c6e;font-size:12px;" target="_blank">[Source]</a>';
  }
  return text;
}

var html = '<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;font-size:15px;max-width:750px;margin:auto;padding:24px;color:#1a1a1a;">';

html += '<div style="background:#1a3c6e;color:#fff;padding:20px;border-radius:6px;margin-bottom:20px;">';
html += '<h1 style="margin:0;font-size:22px;letter-spacing:1px;">GDA EXECUTIVE SITREP</h1>';
html += '<p style="margin:6px 0 0;font-size:13px;opacity:0.85;">Shawn M. Seffernick, President — Envision Innovative Solutions | ' + today + '</p>';
html += '</div>';

html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">BLUF — Bottom Line Up Front</h2>';
html += '<ul style="padding-left:20px;">';
var blufItems = Array.isArray(s.bluf) ? s.bluf : (typeof s.bluf === 'string' ? [s.bluf] : []);
blufItems.forEach(function(b) {
  html += '<li style="margin-bottom:10px;">' + renderWithSource(b) + '</li>';
});
html += '</ul>';

html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">The 2026 Strategic Landscape</h2>';
html += '<p><strong>DOGE &amp; Budget Watch:</strong> ' + renderWithSource((s.strategic_landscape && s.strategic_landscape.doge_watch) || 'Data Unavailable') + '</p>';
html += '<p><strong>INDOPACOM &amp; Global Posture:</strong> ' + renderWithSource((s.strategic_landscape && s.strategic_landscape.indopacom) || 'Data Unavailable') + '</p>';

html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">Defensive Portfolio Watch</h2>';
html += '<p><strong>Incumbency Threat:</strong> ' + renderWithSource((s.defensive_watch && s.defensive_watch.incumbency_threat) || 'Data Unavailable') + '</p>';
html += '<p><strong>Market Pressure:</strong> ' + renderWithSource((s.defensive_watch && s.defensive_watch.market_pressure) || 'Data Unavailable') + '</p>';

html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">Strategic Synthesis — The \"So What?\"</h2>';
html += '<p>' + renderWithSource(s.strategic_synthesis || 'Data Unavailable') + '</p>';

html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">Threat &amp; Opportunity Matrix</h2>';
html += '<table style="width:100%;border-collapse:collapse;font-size:13px;">';
html += '<tr style="background:#1a3c6e;color:#fff;"><th style="padding:8px;text-align:left;">Type</th><th style="padding:8px;text-align:left;">Event</th><th style="padding:8px;text-align:left;">Impact</th><th style="padding:8px;text-align:left;">Action</th></tr>';
(s.threat_opportunity_matrix || []).forEach(function(row, i) {
  var bg = i % 2 === 0 ? '#f5f5f5' : '#ffffff';
  html += '<tr style="background:' + bg + ';">';
  html += '<td style="padding:8px;font-weight:bold;white-space:nowrap;">' + (row.type || '') + '</td>';
  html += '<td style="padding:8px;">' + (row.event || '') + '</td>';
  html += '<td style="padding:8px;">' + (row.impact || '') + '</td>';
  html += '<td style="padding:8px;">' + (row.action || '') + '</td>';
  html += '</tr>';
});
html += '</table>';

html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">Actionable Recommendations</h2>';
html += '<ol style="padding-left:20px;">';
(s.recommendations || []).forEach(function(r) {
  if (typeof r === 'string') {
    html += '<li style="margin-bottom:8px;">' + r + '</li>';
  } else if (typeof r === 'object' && r !== null) {
    html += '<li style="margin-bottom:10px;">';
    html += '<strong>' + (r.action || '') + '</strong>';
    if (r.owner) html += ' <span style="color:#666;font-size:13px;">— ' + r.owner + '</span>';
    if (r.deadline) html += ' <span style="background:#e8f0fe;color:#1a3c6e;padding:1px 6px;border-radius:3px;font-size:12px;">' + r.deadline + '</span>';
    if (r.why) html += '<br><span style="font-size:13px;color:#444;">' + r.why + '</span>';
    html += '</li>';
  }
});
html += '</ol>';

html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">Red Team Analysis</h2>';
(s.red_team || []).forEach(function(rt, i) {
  html += '<div style="background:#fff8f0;border-left:4px solid #c0392b;padding:10px;margin-bottom:10px;">';
  html += '<p style="margin:0;"><strong>Risk ' + (i+1) + ':</strong> ' + (rt.risk || '') + '</p>';
  html += '<p style="margin:4px 0 0;color:#666;"><em>Mitigation:</em> ' + (rt.mitigation || '') + '</p>';
  html += '</div>';
});

if (s.sam_gov_opportunities && s.sam_gov_opportunities.length > 0 && !s.sam_gov_opportunities[0].note) {
  html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">SAM.gov Live Opportunities</h2>';
  html += '<table style="width:100%;border-collapse:collapse;font-size:13px;">';
  html += '<tr style="background:#1a3c6e;color:#fff;"><th style="padding:8px;text-align:left;">Title</th><th style="padding:8px;">Agency</th><th style="padding:8px;">NAICS</th><th style="padding:8px;">Deadline</th></tr>';
  s.sam_gov_opportunities.forEach(function(opp, i) {
    var bg = i % 2 === 0 ? '#f5f5f5' : '#ffffff';
    html += '<tr style="background:' + bg + ';">';
    html += '<td style="padding:8px;">' + (opp.title || '') + '</td>';
    html += '<td style="padding:8px;">' + (opp.agency || '') + '</td>';
    html += '<td style="padding:8px;">' + (opp.naics || '') + '</td>';
    html += '<td style="padding:8px;">' + (opp.deadline || 'TBD') + '</td>';
    html += '</tr>';
  });
  html += '</table>';
}

if (s.top_news && s.top_news.length > 0) {
  html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;margin-top:24px;">Top News</h2>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:12px;margin-bottom:20px;">';
  s.top_news.slice(0,6).forEach(function(news) {
    if (typeof news !== 'object' || !news.title) return;
    html += '<div style="border:1px solid #ddd;border-radius:6px;overflow:hidden;background:#fff;">';
    if (news.image_url && news.image_url !== 'null') {
      html += '<img src="' + news.image_url + '" style="width:100%;height:120px;object-fit:cover;" onerror="this.style.display=\'none\'">';
    }
    html += '<div style="padding:10px;">';
    html += '<p style="margin:0;font-weight:bold;font-size:13px;"><a href="' + (news.url||'#') + '" style="color:#1a3c6e;text-decoration:none;" target="_blank">' + (news.title||'') + '</a></p>';
    if (news.summary) html += '<p style="margin:6px 0 0;font-size:12px;color:#555;">' + news.summary + '</p>';
    html += '</div></div>';
  });
  html += '</div>';
}

var cc = s.command_control || {};
html += '<h2 style="color:#1a3c6e;border-bottom:2px solid #1a3c6e;padding-bottom:4px;">Command &amp; Control — Professional Development</h2>';
html += '<div style="background:#f0f4ff;border-left:4px solid #1a3c6e;padding:12px;">';
html += '<p style="margin:0;"><strong>' + (cc.title || 'Data Unavailable') + '</strong></p>';
if (cc.takeaway) html += '<p style="margin:6px 0 0;">' + cc.takeaway + '</p>';
if (cc.source) html += '<p style="margin:4px 0 0;font-size:13px;"><a href="' + cc.source + '" style="color:#1a3c6e;" target="_blank">' + cc.source + '</a></p>';
html += '</div>';

html += '<hr style="margin-top:30px;border:none;border-top:1px solid #ddd;"/>';
html += '<p style="font-size:12px;color:#999;text-align:center;">GDA Intelligence | Generated by Envision AI Platform | ' + today + '</p>';
html += '</body></html>';

return [{ json: { html_body: html, sitrep: s, full_output: parsed } }];

var dash = {};
var extracted = {};
var t1 = {}, t2 = {}, t3 = {}, sam = {};
var platformData = {};

try { dash = $('Get Dashboard Intelligence').first().json; } catch(e) {}
try { extracted = $('Extract Dashboard Targets').first().json.extracted_targets || {}; } catch(e) {}
try { t1 = $('Tavily Fetch 1').first().json; } catch(e) {}
try { t2 = $('Tavily Fetch 2').first().json; } catch(e) {}
try { t3 = $('Tavily Fetch 3').first().json; } catch(e) {}
try { sam = $('SAM.gov Fetch').first().json; } catch(e) {}
try {
  var pgRow = $('Query Platform State').first().json;
  platformData = pgRow.platform_data || pgRow;
  if (typeof platformData === 'string') platformData = JSON.parse(platformData);
} catch(e) { platformData = {}; }

function fmtTavily(t, label) {
  var results = Array.isArray(t.results) ? t.results : [];
  if (results.length === 0) return label + ': No results\n';
  return label + ':\n' + results.slice(0,8).map(function(r) {
    return '- ' + r.title + ' | ' + (r.content||'').slice(0,200) + ' [' + (r.url||'') + ']';
  }).join('\n') + '\n';
}

var samOpps = [];
try {
  var items = sam.opportunitiesData || sam.data || [];
  samOpps = items.slice(0,5).map(function(o) {
    return {title: o.title, agency: o.fullParentPathName||o.organizationCode, naics: (o.naicsCode||[]).join(','), sol: o.solicitationNumber, posted: o.postedDate, deadline: o.responseDeadLine};
  });
} catch(e) {}

// Build live platform state section from Postgres
var platformSection = '';
if (platformData && platformData.opp_total !== undefined) {
  var deadlines = platformData.upcoming_deadlines || [];
  var actionItems = platformData.open_action_items || [];
  var topByValue = platformData.top_by_value || [];
  platformSection = '=== LIVE EIS GDA PLATFORM STATE (Postgres, real-time) ===\n';
  platformSection += 'PIPELINE: ' + platformData.opp_total + ' active opportunities | Total: $' + platformData.total_value_m + 'M\n';
  platformSection += 'STAGES: Proposal=' + platformData.proposal_count + ' ($' + platformData.proposal_value_m + 'M) | Capture=' + platformData.capture_count + ' ($' + platformData.capture_value_m + 'M) | Qualified=' + platformData.qualified_count + ' ($' + platformData.qualified_value_m + 'M)\n';
  if (deadlines && deadlines.length > 0) {
    platformSection += 'URGENT DEADLINES (next 14 days):\n';
    deadlines.forEach(function(d) { platformSection += '  - ' + d.agency + ' | $' + Math.round((d.estimated_value||0)/1e6) + 'M | ' + d.stage + ' | Due: ' + d.deadline + ' | Fit: ' + d.eis_fit_score + '/100\n'; });
  }
  platformSection += 'ACTIONS: ' + platformData.open_actions + ' open, ' + platformData.overdue_actions + ' OVERDUE\n';
  if (actionItems && actionItems.length > 0) {
    actionItems.slice(0,5).forEach(function(a) { platformSection += '  - [' + a.status + '] ' + a.item + ' (Due: ' + (a.deadline||'TBD') + ')\n'; });
  }
  if (topByValue && topByValue.length > 0) {
    platformSection += 'TOP OPPS BY VALUE:\n';
    topByValue.slice(0,5).forEach(function(o) { platformSection += '  - ' + o.agency + ' | $' + Math.round((o.estimated_value||0)/1e6) + 'M | ' + o.stage + '\n'; });
  }
  platformSection += '=== END PLATFORM STATE ===\n\n';
}

var liveTargets = Array.isArray(extracted.top_programs) ? extracted.top_programs : [];
var dashSummaryText = liveTargets.length > 0
  ? 'LIVE TARGETS:\n' + liveTargets.slice(0,5).map(function(p){return '- ' + p.agency + ' - ' + p.program + ': ' + (p.annual_spend_fmt||'N/A') + '/yr';}).join('\n') + '\n\n'
  : 'DASHBOARD: Unavailable\n\n';

var tavilySection = fmtTavily(t1,'INTEL-DOGE/Agencies') + fmtTavily(t2,'INTEL-INDOPACOM') + fmtTavily(t3,'INTEL-EIS/GDA');
var samSection = samOpps.length > 0 ? 'SAM.GOV:\n' + JSON.stringify(samOpps) + '\n\n' : 'SAM.GOV: No results\n\n';

var oppTotal = platformData.opp_total || 0;
var totalValueM = platformData.total_value_m || 0;
var proposalCount = platformData.proposal_count || 0;
var captureCount = platformData.capture_count || 0;
var qualifiedCount = platformData.qualified_count || 0;
var openActions = platformData.open_actions || 0;
var overdueActions = platformData.overdue_actions || 0;

var topAgenciesJson = JSON.stringify(extracted.top_agencies || []);
var totalSpendFmt = extracted.total_addressable_spend_fmt || 'N/A';
var top3ProgsJson = JSON.stringify(liveTargets.slice(0,3).map(function(p){return {agency:p.agency,program:p.program,spend:p.annual_spend_fmt};}));
var samOppsJson = JSON.stringify(samOpps.length > 0 ? samOpps : [{note:'no SAM results'}]);

var prompt = platformSection + dashSummaryText + tavilySection + samSection +
  'TASK: You are the GDA Command daily intelligence briefer for Shawn Seffernick, President of EIS. FY26 target: $100M.\n\nBased on ALL data above, generate this EXACT JSON structure:\n\n{\n  "sitrep": {\n    "generated_at": "[ISO datetime]",\n    "bluf": ["[Finding 1 — MUST use numbers from LIVE PLATFORM STATE: cite opp count, dollar amounts, stage]", "[Finding 2 — market intel with source URL]", "[Finding 3 — competitive threat with source URL]"],\n    "pipeline_status": {"total_opps": ' + oppTotal + ', "total_value_m": ' + totalValueM + ', "proposal_count": ' + proposalCount + ', "capture_count": ' + captureCount + ', "qualified_count": ' + qualifiedCount + ', "summary": "[1-2 sentences on pipeline health based on the ' + oppTotal + ' opps and $' + totalValueM + 'M total value]"},\n    "critical_actions": ["[Most urgent action based on platform deadlines/overdue items]", "[Second priority action]", "[Third priority action]"],\n    "risk_summary": {"count": ' + overdueActions + ', "top_risks": ["[Primary risk to revenue/pipeline]", "[Secondary risk]"]},\n    "department_coverage": {"active_departments": ["[list DoD dept names that have active opps in our pipeline]"], "gaps": ["[DoD/federal depts not in our pipeline]"], "recommendation": "[which dept gap to close first and why]"},\n    "trading": {"status": "monitoring", "summary": "No active positions. Engine monitoring markets."},\n    "strategic_landscape": {"doge_watch": "[Specific budget impact]", "indopacom": "[Specific awards/exercises]"},\n    "defensive_watch": {"incumbency_threat": "[Named programs at risk]", "market_pressure": "[Pricing pressures]"},\n    "strategic_synthesis": "[2-3 sentences: connect platform pipeline ($' + totalValueM + 'M across ' + oppTotal + ' opps) to market intel and $100M target]",\n    "dashboard_summary": {"top_agencies": ' + topAgenciesJson + ', "total_addressable_spend": "' + totalSpendFmt + '", "top_programs": ' + top3ProgsJson + '},\n    "threat_opportunity_matrix": [{"type": "Opportunity", "event": "[specific program]", "impact": "High", "action": "[action with role]"}, {"type": "Risk", "event": "[specific threat]", "impact": "High", "action": "[mitigation]"}],\n    "recommendations": [{"action": "[specific action]", "owner": "[BD Lead|Capture Manager|President|CTO]", "deadline": "[date]", "why": "[dollar impact]"}, {"action": "[action2]", "owner": "[role]", "deadline": "[date]", "why": "[reason]"}, {"action": "[action3]", "owner": "[role]", "deadline": "[date]", "why": "[reason]"}],\n    "red_team": [{"risk": "[competitor/program]", "mitigation": "[countermove]"}, {"risk": "[r2]", "mitigation": "[m2]"}, {"risk": "[r3]", "mitigation": "[m3]"}],\n    "command_control": {"title": "[Most important headline today]", "takeaway": "[One sentence CEO acts on immediately]", "source": "[URL]"},\n    "sam_gov_opportunities": ' + samOppsJson + ',\n    "top_news": [{"title": "[headline]", "summary": "[1-2 sentences]", "url": "[URL]", "image_url": null}]\n  }\n}\n\nCRITICAL: pipeline_status numbers MUST be ' + oppTotal + ' opps and $' + totalValueM + 'M from LIVE PLATFORM STATE. Do NOT estimate — use exact numbers.';

return [{ json: { prompt: prompt } }];

// Read dashboard response
var dashData = {};
try { dashData = $('Get Dashboard Intelligence').first().json; } catch(e) {}

// Extract all programs from nested or flat structure
var allPrograms = [];
var agencies = Array.isArray(dashData.agencies) ? dashData.agencies
             : Array.isArray(dashData.agency_programs) ? dashData.agency_programs : [];

for (var ag of agencies) {
  var agencyName = ag.agency || ag.name || 'Unknown';
  if (Array.isArray(ag.commands)) {
    for (var cmd of ag.commands) {
      var cmdName = cmd.command || cmd.name || '';
      if (Array.isArray(cmd.programs)) {
        for (var prog of cmd.programs) {
          allPrograms.push({ agency: agencyName, command: cmdName,
            program: prog.program_office || prog.name || 'Unknown',
            annual_spend: Number(prog.annual_spend) || 0,
            need_score: Number(prog.need_score) || 0,
            eis_fit_score: Number(prog.eis_fit_score) || 0,
            capability_need: prog.capability_need || '', eis_fit: prog.eis_fit || '' });
        }
      }
    }
  } else if (Array.isArray(ag.programs)) {
    for (var prog of ag.programs) {
      allPrograms.push({ agency: agencyName, command: '',
        program: prog.program_office || prog.name || 'Unknown',
        annual_spend: Number(prog.annual_spend) || 0,
        need_score: Number(prog.need_score) || 0,
        eis_fit_score: Number(prog.eis_fit_score) || 0,
        capability_need: prog.capability_need || '', eis_fit: prog.eis_fit || '' });
    }
  }
}

// Sort by combined priority score
allPrograms.sort((a, b) => (b.need_score + b.eis_fit_score) - (a.need_score + a.eis_fit_score));

var top5 = allPrograms.slice(0, 5);
var top3Agencies = [...new Set(top5.map(p => p.agency))].slice(0, 3);
var topCapabilities = [...new Set(top5.flatMap(p => (p.capability_need || '').split(/[,\/]/).map(c => c.trim()).filter(c => c.length > 2)))].slice(0, 4);

var agencyStr = top3Agencies.length > 0 ? top3Agencies.join(' ') : 'SOCOM TRADOC PEO STRI';
var capStr = topCapabilities.length > 0 ? topCapabilities.join(' ') : 'training simulation XR digital readiness';

// Build dynamic queries scoped to GDA market
var dynamicQuery1 = '(' + agencyStr + ') ' + capStr + ' contract award budget 2026 DOGE defense spending';
var dynamicQuery2 = 'INDOPACOM "first island chain" defense logistics training simulation contract technology 2026';
var dynamicQuery3 = '"Envision Innovative Solutions" OR "PD Systems" OR "Riverstone" defense contract training simulation XR digital readiness 2026';

var totalSpend = top5.reduce((sum, p) => sum + p.annual_spend, 0);

var dashboardSummary = {
  top_agencies: top3Agencies,
  top_programs: top5.map(p => ({
    agency: p.agency, command: p.command, program: p.program,
    annual_spend_usd: p.annual_spend,
    annual_spend_fmt: p.annual_spend >= 1e9 ? '$' + (p.annual_spend/1e9).toFixed(1) + 'B'
                     : p.annual_spend >= 1e6 ? '$' + (p.annual_spend/1e6).toFixed(0) + 'M' : '$' + p.annual_spend,
    need_score: p.need_score, eis_fit_score: p.eis_fit_score,
    capability: p.capability_need
  })),
  total_addressable_spend_usd: totalSpend,
  total_addressable_spend_fmt: totalSpend >= 1e9 ? '$' + (totalSpend/1e9).toFixed(1) + 'B'
                               : '$' + (totalSpend/1e6).toFixed(0) + 'M'
};

return [{
  json: {
    ...dashData,
    extracted_targets: dashboardSummary,
    tavily_query_1: dynamicQuery1,
    tavily_query_2: dynamicQuery2,
    tavily_query_3: dynamicQuery3
  }
}];

const input = $input.first()?.json || {};
const s = input.sitrep || {};
const now = new Date().toISOString();
const findings = [];

function cleanFinding(text) {
  if (!text) return null;
  var t = String(text);
  t = t.replace(/\|\s*[Ss]ource:[^|\n]*/g, '');
  t = t.replace(/<[^>]+>/g, ' ');
  t = t.replace(/[\u0080-\uFFFF]/g, '');
  t = t.replace(/["'\\]/g, '');
  t = t.replace(/\s+/g, ' ').trim();
  var dot = t.search(/[.!?]/);
  if (dot > 20 && dot < 180) t = t.substring(0, dot + 1);
  else t = t.substring(0, 180);
  return t.trim() || null;
}

